select id, username, password, email, bio, image
from users
where id = #{id}

select id, username, password, email, bio, image
from users
where username = #{username}

select id, username, password, email, bio, image
from users
where email = #{email}

select user_id as userId, follow_id as targetId
from follows
where user_id = #{userId} and follow_id = #{targetId}
